32		async findTopCopurchases({
33			styleId,
34			limit = 4,
35			excludeIds = [],
36		}: {
37			styleId: number;
38			limit?: number;
39			excludeIds?: number[];
40		}): Promise<{ paired_style_id: number; copurchase_count: number }[]> {
41			const dto = plainToInstance(FindTopCopurchasesDto, { styleId, limit, excludeIds });
42			const errors = await validate(dto);
43			if (errors.length > 0) {
44				throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
45			}
46	
47			try {
48				const queryA = this.knexRead(this.tableName)
49					.select('style_id_b as paired_style_id', 'copurchase_count')
50					.where({ style_id_a: styleId })
51					.whereNull('deleted_at');
52	
53				const queryB = this.knexRead(this.tableName)
54					.select('style_id_a as paired_style_id', 'copurchase_count')
55					.where({ style_id_b: styleId })
56					.whereNull('deleted_at');
57	
58				if (excludeIds.length > 0) {
59					queryA.whereNotIn('style_id_b', excludeIds);
60					queryB.whereNotIn('style_id_a', excludeIds);
61				}
62	
63				const results = await this.knexRead
64					.unionAll([queryA, queryB])
65					.orderBy('copurchase_count', 'desc')
66					.limit(limit);
67	
68				this.logger.debug(`Found ${results.length} copurchases for style ${styleId}`);
69	
70				return results.map(
71					(row: {
72						paired_style_id: number | string;
73						copurchase_count: number | string;
74					}) => ({
75						paired_style_id: Number(row.paired_style_id),
76						copurchase_count: Number(row.copurchase_count),
77					}),
78				);
79			} catch (error: unknown) {
80				const err = error instanceof Error ? error : new Error(String(error));
81				this.logger.error(
82					`Failed to find top copurchases for style ${styleId}: ${err.message}`,
83				);
84				throw err;
85			}
86		}
