212		async bulkInsert(
213			pairs: {
214				styleIdA: number;
215				styleIdB: number;
216				copurchaseCount: number;
217			}[],
218		): Promise<void> {
219			try {
220				const dataToInsert = pairs.map((pair) => {
221					const minId = Math.min(pair.styleIdA, pair.styleIdB);
222					const maxId = Math.max(pair.styleIdA, pair.styleIdB);
223	
224					return {
225						_id: randomUUID(),
226						style_id_a: minId,
227						style_id_b: maxId,
228						copurchase_count: pair.copurchaseCount,
229						created_at: this.knexWrite.fn.now(),
230						updated_at: this.knexWrite.fn.now(),
231						deleted_at: null,
232					};
233				});
234	
235				const batchSize = 1000;
236				for (let i = 0; i < dataToInsert.length; i += batchSize) {
237					const batch = dataToInsert.slice(i, i + batchSize);
238	
239					await this.knexWrite(this.tableName).insert(batch);
240	
241					this.logger.debug(
242						`Processed batch ${Math.floor(i / batchSize) + 1}/${Math.ceil(dataToInsert.length / batchSize)} (${batch.length} records)`,
243					);
244				}
245	
246				this.logger.debug(`Successfully inserted ${pairs.length} style copurchases`);
247			} catch (error: unknown) {
248				const err = error instanceof Error ? error : new Error(String(error));
249				this.logger.error(`Failed to bulk insert style copurchases: ${err.message}`);
250				throw err;
251			}
252		}
253	
254		async clearExistingData(): Promise<void> {
255			try {
256				await this.knexWrite.raw(`TRUNCATE TABLE \`${this.tableName}\``);
257				this.logger.log('Truncated style_copurchases table');
258			} catch (error: unknown) {
259				const err = error instanceof Error ? error : new Error(String(error));
260				this.logger.error(`Failed to truncate style copurchases: ${err.message}`);
261				throw err;
262			}
263		}
264	
265		async getRecordCount(): Promise<number> {
266			try {
267				const result = await this.knexRead(this.tableName)
268					.whereNull('deleted_at')
269					.count('_id as count')
270					.first();
271	
272				return Number(result?.['count'] ?? 0);
273			} catch (error: unknown) {
274				const err = error instanceof Error ? error : new Error(String(error));
275				this.logger.error(
276					`Failed to get record count for style copurchases: ${err.message}`,
277				);
278				throw err;
279			}
280		}
281	
282		private formatValidationErrors(errors: ValidationError[]): string {
283			return errors
284				.map(
285					(error) =>
286						`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
287				)
288				.join('; ');
289		}
290	}
